WITH weak_pairs AS (SELECT Carrier, OriginCode, count() AS winter_flights, round(avg(if(DepDel15 = 0, 1.0, 0.0)) * 100, 2) AS dep_otp_pct, round(avg(ifNull(toFloat64(DepDelay), 0.0)), 2) AS avg_dep_delay_min FROM ontime.fact_ontime WHERE Month IN (12, 1, 2) AND Cancelled = 0 AND Diverted = 0 GROUP BY Carrier, OriginCode HAVING winter_flights >= 1000 ORDER BY dep_otp_pct ASC, avg_dep_delay_min DESC LIMIT 10) SELECT 'carrier' AS concentration_type, Carrier AS entity, count() AS weak_pair_count, round(count() * 100.0 / (SELECT count() FROM weak_pairs), 1) AS weak_pair_share_pct FROM weak_pairs GROUP BY Carrier UNION ALL SELECT 'airport' AS concentration_type, OriginCode AS entity, count() AS weak_pair_count, round(count() * 100.0 / (SELECT count() FROM weak_pairs), 1) AS weak_pair_share_pct FROM weak_pairs GROUP BY OriginCode ORDER BY concentration_type, weak_pair_count DESC, entity ASC
